Binary serialization formats like gob are significantly more dangerous than JSON because they can encode type information and potentially instantiate arbitrary types. Go's gob decoder is safer than Java serialization, but still requires careful handling.

**PRODUCTION PATTERN**:

```go
package main

import (
	"bytes"
	"context"
	"crypto/hmac"
	"crypto/sha256"
	"encoding/gob"
	"encoding/hex"
	"errors"
	"fmt"
	"io"
	"log"
	"sync"
	"time"
)

const (
	MaxMessageSize     = 64 * 1024 // 64KB max for inter-service messages
	SignatureSize      = 64        // SHA256 HMAC hex encoded
	DecodeTimeout      = 5 * time.Second
	MaxConcurrentDecodes = 100
)

var (
	ErrInvalidSignature = errors.New("invalid message signature")
	ErrMessageTooLarge  = errors.New("message exceeds size limit")
	ErrDecodeTimeout    = errors.New("decode operation timed out")
	ErrTooManyDecodes   = errors.New("too many concurrent decode operations")
)

// ServiceMessage is the ONLY type allowed for inter-service communication
type ServiceMessage struct {
	MessageID   string            `json:"message_id"`
	ServiceName string            `json:"service_name"`
	Action      string            `json:"action"`
	Payload     map[string]string `json:"payload"` // String-only payload
	Timestamp   int64             `json:"timestamp"`
	Version     int               `json:"version"`
}

// ValidActions defines the allowlist of permitted actions
var ValidActions = map[string]bool{
	"user.create":  true,
	"user.update":  true,
	"user.delete":  true,
	"order.create": true,
	"order.status": true,
}

// ValidServices defines trusted service names
var ValidServices = map[string]bool{
	"user-service":  true,
	"order-service": true,
	"auth-service":  true,
}

func (m *ServiceMessage) Validate() error {
	if m.MessageID == "" || len(m.MessageID) > 64 {
		return errors.New("invalid message_id")
	}

	if !ValidServices[m.ServiceName] {
		return fmt.Errorf("unknown service: %s", m.ServiceName)
	}

	if !ValidActions[m.Action] {
		return fmt.Errorf("invalid action: %s", m.Action)
	}

	// Validate timestamp (within 5 minutes)
	now := time.Now().Unix()
	if m.Timestamp < now-300 || m.Timestamp > now+60 {
		return errors.New("message timestamp out of acceptable range")
	}

	if m.Version < 1 || m.Version > 10 {
		return errors.New("unsupported message version")
	}

	// Validate payload size
	if len(m.Payload) > 50 {
		return errors.New("payload has too many fields")
	}

	for key, value := range m.Payload {
		if len(key) > 64 || len(value) > 1024 {
			return errors.New("payload field too large")
		}
	}

	return nil
}

// SecureGobCodec provides safe serialization/deserialization
type SecureGobCodec struct {
	secretKey      []byte
	decodeSemaphore chan struct{}
	mu             sync.RWMutex
	decodeCount    int64
	decodeErrors   int64
}

func NewSecureGobCodec(secretKey []byte) *SecureGobCodec {
	if len(secretKey) < 32 {
		panic("secret key must be at least 32 bytes")
	}

	// Register only allowed types
	gob.Register(ServiceMessage{})

	return &SecureGobCodec{
		secretKey:      secretKey,
		decodeSemaphore: make(chan struct{}, MaxConcurrentDecodes),
	}
}

// Sign creates HMAC signature for data integrity
func (c *SecureGobCodec) Sign(data []byte) string {
	h := hmac.New(sha256.New, c.secretKey)
	h.Write(data)
	return hex.EncodeToString(h.Sum(nil))
}

// VerifySignature validates HMAC signature
func (c *SecureGobCodec) VerifySignature(data []byte, signature string) bool {
	expected := c.Sign(data)
	return hmac.Equal([]byte(expected), []byte(signature))
}

// Encode serializes and signs a ServiceMessage
func (c *SecureGobCodec) Encode(msg *ServiceMessage) ([]byte, string, error) {
	// Validate before encoding
	if err := msg.Validate(); err != nil {
		return nil, "", fmt.Errorf("validation failed: %w", err)
	}

	var buf bytes.Buffer
	encoder := gob.NewEncoder(&buf)

	if err := encoder.Encode(msg); err != nil {
		return nil, "", fmt.Errorf("encode failed: %w", err)
	}

	data := buf.Bytes()

	// Check size limit
	if len(data) > MaxMessageSize {
		return nil, "", ErrMessageTooLarge
	}

	signature := c.Sign(data)
	return data, signature, nil
}

// Decode safely deserializes a signed ServiceMessage
func (c *SecureGobCodec) Decode(ctx context.Context, data []byte, signature string) (*ServiceMessage, error) {
	// DEFENSE 1: Rate limit concurrent decodes
	select {
	case c.decodeSemaphore <- struct{}{}:
		defer func() { <-c.decodeSemaphore }()
	default:
		c.incrementErrors()
		return nil, ErrTooManyDecodes
	}

	// DEFENSE 2: Size limit check
	if len(data) > MaxMessageSize {
		c.incrementErrors()
		return nil, ErrMessageTooLarge
	}

	// DEFENSE 3: Verify signature BEFORE deserializing
	if !c.VerifySignature(data, signature) {
		c.incrementErrors()
		log.Printf("SECURITY: Invalid signature detected, data length: %d", len(data))
		return nil, ErrInvalidSignature
	}

	// DEFENSE 4: Timeout for decode operation
	ctx, cancel := context.WithTimeout(ctx, DecodeTimeout)
	defer cancel()

	resultCh := make(chan *ServiceMessage, 1)
	errorCh := make(chan error, 1)

	go func() {
		var msg ServiceMessage
		decoder := gob.NewDecoder(bytes.NewReader(data))

		if err := decoder.Decode(&msg); err != nil {
			errorCh <- fmt.Errorf("decode failed: %w", err)
			return
		}

		// DEFENSE 5: Validate deserialized content
		if err := msg.Validate(); err != nil {
			errorCh <- fmt.Errorf("validation failed: %w", err)
			return
		}

		resultCh <- &msg
	}()

	select {
	case msg := <-resultCh:
		c.incrementSuccess()
		return msg, nil
	case err := <-errorCh:
		c.incrementErrors()
		return nil, err
	case <-ctx.Done():
		c.incrementErrors()
		return nil, ErrDecodeTimeout
	}
}

func (c *SecureGobCodec) incrementSuccess() {
	c.mu.Lock()
	c.decodeCount++
	c.mu.Unlock()
}

func (c *SecureGobCodec) incrementErrors() {
	c.mu.Lock()
	c.decodeErrors++
	c.mu.Unlock()
}

// GetMetrics returns codec statistics for monitoring
func (c *SecureGobCodec) GetMetrics() (total, errors int64) {
	c.mu.RLock()
	defer c.mu.RUnlock()
	return c.decodeCount, c.decodeErrors
}

func main() {
	// Production: Load from secure key management
	secretKey := []byte("this-is-a-32-byte-secret-key!!!")
	codec := NewSecureGobCodec(secretKey)

	// Encode message
	msg := &ServiceMessage{
		MessageID:   "msg-12345",
		ServiceName: "user-service",
		Action:      "user.create",
		Payload: map[string]string{
			"username": "newuser",
			"email":    "user@example.com",
		},
		Timestamp: time.Now().Unix(),
		Version:   1,
	}

	data, signature, err := codec.Encode(msg)
	if err != nil {
		log.Fatalf("Encode error: %v", err)
	}

	fmt.Printf("Encoded %d bytes, signature: %s\n", len(data), signature[:16]+"...")

	// Decode message
	ctx := context.Background()
	decoded, err := codec.Decode(ctx, data, signature)
	if err != nil {
		log.Fatalf("Decode error: %v", err)
	}

	fmt.Printf("Decoded message: %+v\n", decoded)

	// Show metrics
	total, errors := codec.GetMetrics()
	fmt.Printf("Metrics - Total: %d, Errors: %d\n", total, errors)
}
