- **Timing-safe comparison**: Prevents timing attacks on signature verification

When you need to serialize complex types beyond JSON's capabilities, you must use a safe serialization format with explicit type handling and strict validation. Never allow arbitrary type instantiation from user input.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const crypto = require('crypto');
const Ajv = require('ajv');
const addFormats = require('ajv-formats');

const app = express();
app.use(express.json());

const SECRET_KEY = Buffer.from(process.env.SESSION_SECRET, 'hex');
const ajv = new Ajv({ allErrors: true, removeAdditional: 'all' });
addFormats(ajv);

// SAFE: Define allowed types with explicit serializers/deserializers
const TYPE_HANDLERS = {
  'Date': {
    serialize: (val) => val.toISOString(),
    deserialize: (val) => {
      const date = new Date(val);
      if (isNaN(date.getTime())) throw new Error('Invalid date');
      return date;
    },
    validate: (val) => typeof val === 'string' && /^\d{4}-\d{2}-\d{2}T/.test(val)
  },
  'RegExp': {
    // SAFE: Only allow predefined patterns, never user-defined regex
    serialize: (val) => val.source,
    deserialize: (val) => {
      const allowedPatterns = ['email', 'phone', 'alphanumeric'];
      const patternMap = {
        'email': /^[^\s@]+@[^\s@]+\.[^\s@]+$/,
        'phone': /^\+?[1-9]\d{1,14}$/,
        'alphanumeric': /^[a-zA-Z0-9]+$/
      };
      if (!allowedPatterns.includes(val)) {
        throw new Error('Invalid pattern identifier');
      }
      return patternMap[val];
    },
    validate: (val) => ['email', 'phone', 'alphanumeric'].includes(val)
  },
  'Buffer': {
    serialize: (val) => val.toString('base64'),
    deserialize: (val) => {
      if (typeof val !== 'string' || val.length > 1048576) {
        throw new Error('Invalid buffer');
      }
      return Buffer.from(val, 'base64');
    },
    validate: (val) => typeof val === 'string' && val.length <= 1048576
  }
};

// SAFE: Custom serializer that only handles allowed types
function safeSerialize(obj, depth = 0) {
  if (depth > 10) throw new Error('Max depth exceeded');

  if (obj === null || obj === undefined) return obj;

  const type = Object.prototype.toString.call(obj).slice(8, -1);

  if (['String', 'Number', 'Boolean'].includes(type)) {
    return obj;
  }

  if (TYPE_HANDLERS[type]) {
    return {
      __type: type,
      __value: TYPE_HANDLERS[type].serialize(obj)
    };
  }

  if (Array.isArray(obj)) {
    return obj.map(item => safeSerialize(item, depth + 1));
  }

  if (type === 'Object') {
    const result = {};
    for (const [key, value] of Object.entries(obj)) {
      // SAFE: Reject keys that could cause prototype pollution
      if (['__proto__', 'constructor', 'prototype'].includes(key)) {
        throw new Error('Invalid key');
      }
      result[key] = safeSerialize(value, depth + 1);
    }
    return result;
  }

  throw new Error(`Unsupported type: ${type}`);
}

// SAFE: Custom deserializer with strict type checking
function safeDeserialize(obj, depth = 0) {
  if (depth > 10) throw new Error('Max depth exceeded');

  if (obj === null || obj === undefined) return obj;
  if (typeof obj !== 'object') return obj;

  // Handle typed objects
  if (obj.__type && obj.__value !== undefined) {
    const handler = TYPE_HANDLERS[obj.__type];
    if (!handler) throw new Error(`Unknown type: ${obj.__type}`);
    if (!handler.validate(obj.__value)) throw new Error('Validation failed');
    return handler.deserialize(obj.__value);
  }

  if (Array.isArray(obj)) {
    return obj.map(item => safeDeserialize(item, depth + 1));
  }

  // SAFE: Create object without prototype chain issues
  const result = Object.create(null);
  for (const [key, value] of Object.entries(obj)) {
    if (['__proto__', 'constructor', 'prototype'].includes(key)) {
      throw new Error('Invalid key');
    }
    result[key] = safeDeserialize(value, depth + 1);
  }
  return result;
}

// PRODUCTION: Complete session management with audit logging
class SecureSessionManager {
  constructor(secretKey, options = {}) {
    this.secretKey = secretKey;
    this.maxAge = options.maxAge || 3600000; // 1 hour
    this.algorithm = 'aes-256-gcm';
  }

  // SAFE: Encrypt and sign session data
  createSession(data) {
    const serialized = JSON.stringify(safeSerialize(data));
    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv(this.algorithm, this.secretKey, iv);

    let encrypted = cipher.update(serialized, 'utf8', 'hex');
    encrypted += cipher.final('hex');
    const authTag = cipher.getAuthTag().toString('hex');

    const payload = {
      iv: iv.toString('hex'),
      data: encrypted,
      tag: authTag,
      exp: Date.now() + this.maxAge
    };

    return Buffer.from(JSON.stringify(payload)).toString('base64');
  }

  // SAFE: Decrypt and validate session data
  verifySession(token) {
    try {
      const payload = JSON.parse(Buffer.from(token, 'base64').toString());

      // Check expiration
      if (!payload.exp || Date.now() > payload.exp) {
        return { valid: false, error: 'Session expired' };
      }

      const decipher = crypto.createDecipheriv(
        this.algorithm,
        this.secretKey,
        Buffer.from(payload.iv, 'hex')
      );
      decipher.setAuthTag(Buffer.from(payload.tag, 'hex'));

      let decrypted = decipher.update(payload.data, 'hex', 'utf8');
      decrypted += decipher.final('utf8');

      const data = safeDeserialize(JSON.parse(decrypted));
      return { valid: true, data };
    } catch (error) {
      return { valid: false, error: 'Invalid session' };
    }
  }
}

