    res.status(400).json({ error: 'Invalid request' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **JSON.parse only**: Express's built-in JSON parser uses safe JSON.parse(), never eval() or custom deserializers
- **Schema validation with AJV**: Strict schemas reject unexpected properties and validate types
- **Whitelist reconstruction**: Only copy explicitly allowed fields to prevent prototype pollution
- **additionalProperties: false**: Rejects any fields not defined in schema
- **Size limits**: Prevents denial of service via large payloads

Excellent question! Handling complex data types safely requires a custom serialization strategy that avoids code execution. Here's a production-ready approach using type-tagged serialization with strict validation.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const Ajv = require('ajv');
const addFormats = require('ajv-formats');
const crypto = require('crypto');

const app = express();
const ajv = new Ajv({ allErrors: true, removeAdditional: true });
addFormats(ajv);

// Safe type-tagged serializer/deserializer
class SafeSerializer {
  static ALLOWED_TYPES = new Set(['Date', 'Map', 'Set', 'Buffer']);
  static MAX_DEPTH = 10;
  static MAX_SIZE = 100000; // 100KB

  // Serialize complex types to safe JSON representation
  static serialize(obj, depth = 0) {
    if (depth > this.MAX_DEPTH) {
      throw new Error('Maximum serialization depth exceeded');
    }

    if (obj === null || obj === undefined) return obj;

    if (obj instanceof Date) {
      return { __type: 'Date', value: obj.toISOString() };
    }

    if (obj instanceof Map) {
      const entries = Array.from(obj.entries()).map(
        ([k, v]) => [this.serialize(k, depth + 1), this.serialize(v, depth + 1)]
      );
      return { __type: 'Map', value: entries };
    }

    if (obj instanceof Set) {
      const values = Array.from(obj).map(v => this.serialize(v, depth + 1));
      return { __type: 'Set', value: values };
    }

    if (Buffer.isBuffer(obj)) {
      return { __type: 'Buffer', value: obj.toString('base64') };
    }

    if (Array.isArray(obj)) {
      return obj.map(item => this.serialize(item, depth + 1));
    }

    if (typeof obj === 'object') {
      // CRITICAL: Only serialize plain objects, reject class instances
      if (obj.constructor !== Object) {
        throw new Error(`Unsupported type: ${obj.constructor.name}`);
      }
      const result = {};
      for (const [key, value] of Object.entries(obj)) {
        // Reject keys that could cause prototype pollution
        if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
          throw new Error(`Dangerous key rejected: ${key}`);
        }
        result[key] = this.serialize(value, depth + 1);
      }
      return result;
    }

    // Primitives pass through
    if (['string', 'number', 'boolean'].includes(typeof obj)) {
      return obj;
    }

    throw new Error(`Cannot serialize type: ${typeof obj}`);
  }

  // Safely deserialize with strict type checking
  static deserialize(obj, depth = 0) {
    if (depth > this.MAX_DEPTH) {
      throw new Error('Maximum deserialization depth exceeded');
    }

    if (obj === null || obj === undefined) return obj;

    // Handle type-tagged objects
    if (typeof obj === 'object' && obj.__type) {
      if (!this.ALLOWED_TYPES.has(obj.__type)) {
        throw new Error(`Disallowed type: ${obj.__type}`);
      }

      switch (obj.__type) {
        case 'Date': {
          const date = new Date(obj.value);
          if (isNaN(date.getTime())) {
            throw new Error('Invalid date value');
          }
          return date;
        }
        case 'Map': {
          if (!Array.isArray(obj.value)) {
            throw new Error('Invalid Map format');
          }
          return new Map(
            obj.value.map(([k, v]) => [
              this.deserialize(k, depth + 1),
              this.deserialize(v, depth + 1)
            ])
          );
        }
        case 'Set': {
          if (!Array.isArray(obj.value)) {
            throw new Error('Invalid Set format');
          }
          return new Set(
            obj.value.map(v => this.deserialize(v, depth + 1))
          );
        }
        case 'Buffer': {
          if (typeof obj.value !== 'string') {
            throw new Error('Invalid Buffer format');
          }
          return Buffer.from(obj.value, 'base64');
        }
      }
    }

    if (Array.isArray(obj)) {
      return obj.map(item => this.deserialize(item, depth + 1));
    }

    if (typeof obj === 'object') {
      const result = Object.create(null); // No prototype
      for (const [key, value] of Object.entries(obj)) {
        // Reject dangerous keys
        if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
          throw new Error(`Dangerous key rejected: ${key}`);
        }
        result[key] = this.deserialize(value, depth + 1);
      }
      return result;
    }

    return obj;
  }
}

// Integrity verification with HMAC
class IntegrityVerifier {
  constructor(secret) {
    this.secret = secret;
  }

  sign(data) {
    const json = JSON.stringify(data);
    const hmac = crypto.createHmac('sha256', this.secret)
      .update(json)
      .digest('base64url');
    return { data: json, signature: hmac };
  }

  verify(payload) {
    if (!payload.data || !payload.signature) {
      throw new Error('Missing data or signature');
    }

    const expectedHmac = crypto.createHmac('sha256', this.secret)
      .update(payload.data)
      .digest('base64url');

    // Timing-safe comparison
    if (!crypto.timingSafeEqual(
      Buffer.from(payload.signature),
      Buffer.from(expectedHmac)
    )) {
      throw new Error('Signature verification failed');
    }

    return JSON.parse(payload.data);
  }
}

// Production middleware setup
const verifier = new IntegrityVerifier(process.env.SERIALIZATION_SECRET || crypto.randomBytes(32));

app.post('/api/restore-state', express.json({ limit: '100kb' }), async (req, res) => {
  const startTime = Date.now();
  const requestId = crypto.randomUUID();

  try {
    // Step 1: Verify integrity signature
    const verifiedData = verifier.verify(req.body);

    // Step 2: Size check
    if (JSON.stringify(verifiedData).length > SafeSerializer.MAX_SIZE) {
      throw new Error('Payload too large');
    }

    // Step 3: Safe deserialization
    const state = SafeSerializer.deserialize(verifiedData);

    // Step 4: Business logic validation
    if (!state.userId || typeof state.userId !== 'number') {
      throw new Error('Invalid state: missing userId');
    }

    // Audit log
    console.log(JSON.stringify({
      event: 'state_restored',
      requestId,
      userId: state.userId,
      ip: req.ip,
      duration: Date.now() - startTime
    }));

    res.json({ success: true, requestId });

  } catch (error) {
    // Security event logging
    console.error(JSON.stringify({
      event: 'state_restore_failed',
      requestId,
      error: error.message,
      ip: req.ip,
      userAgent: req.headers['user-agent']
    }));

    res.status(400).json({
      error: 'Invalid state data',
      requestId
    });
  }
});

// Endpoint to create signed state
app.post('/api/save-state', express.json({ limit: '100kb' }), (req, res) => {
  try {
    const serialized = SafeSerializer.serialize(req.body.state);
    const signed = verifier.sign(serialized);
    res.json(signed);
  } catch (error) {
    res.status(400).json({ error: 'Cannot serialize state' });
  }
});

app.listen(3000);
```

**Defense in Depth Layers**:
1. **HMAC Integrity Verification**: Data cannot be tampered with without the secret key, preventing injection of malicious type tags
2. **Type Whitelist**: Only explicitly allowed types (Date, Map, Set, Buffer) can be deserialized
3. **Prototype Pollution Prevention**: Uses Object.create(null) and rejects __proto__, constructor, prototype keys
4. **Depth Limiting**: Prevents stack overflow attacks via deeply nested objects

**Additional Protections**:
- **Timing-safe comparison**: Prevents timing attacks on signature verification using crypto.timingSafeEqual()
- **Size limits**: Both at Express level (100kb) and serializer level to prevent DoS
- **Structured logging**: All deserialization events logged with request IDs for incident response
- **No eval or Function constructors**: Type restoration uses explicit constructors only
- **Request ID tracking**: Every request gets a UUID for audit trail and debugging
